#ifndef FAST_VECTOR_MATH_H
#define FAST_VECTOR_MATH_H

#include <godot_cpp/classes/ref_counted.hpp>
#include <godot_cpp/variant/array.hpp>
#include <godot_cpp/variant/packed_vector3_array.hpp>
#include <godot_cpp/variant/vector3.hpp>

using namespace godot;

class FastVectorMath : public RefCounted {
	GDCLASS(FastVectorMath, RefCounted);

protected:
	static void _bind_methods();

public:
	FastVectorMath() {}
	~FastVectorMath() {}

	static float dot_product(const Vector3 &a, const Vector3 &b);
	static Vector3 cross_product(const Vector3 &a, const Vector3 &b);
	static Array compute_centroid_and_bounds(const PackedVector3Array &points);
	static float ray_sphere_intersection(const Vector3 &origin, const Vector3 &dir,
			const Vector3 &sphere_center, float radius);
};

#endif // FAST_VECTOR_MATH_H

#include "fast_vector_math.h"

#include <godot_cpp/core/class_db.hpp>
#include <cmath>

using namespace godot;

void FastVectorMath::_bind_methods() {
	ClassDB::bind_static_method("FastVectorMath", D_METHOD("dot_product", "a", "b"), &FastVectorMath::dot_product);
	ClassDB::bind_static_method("FastVectorMath", D_METHOD("cross_product", "a", "b"), &FastVectorMath::cross_product);
	ClassDB::bind_static_method("FastVectorMath", D_METHOD("compute_centroid_and_bounds", "points"), &FastVectorMath::compute_centroid_and_bounds);
	ClassDB::bind_static_method("FastVectorMath", D_METHOD("ray_sphere_intersection", "origin", "dir", "sphere_center", "radius"), &FastVectorMath::ray_sphere_intersection);
}

float FastVectorMath::dot_product(const Vector3 &a, const Vector3 &b) {
	return a.x * b.x + a.y * b.y + a.z * b.z;
}

Vector3 FastVectorMath::cross_product(const Vector3 &a, const Vector3 &b) {
	return Vector3(
			a.y * b.z - a.z * b.y,
			a.z * b.x - a.x * b.z,
			a.x * b.y - a.y * b.x);
}

Array FastVectorMath::compute_centroid_and_bounds(const PackedVector3Array &points) {
	Array result;

	int64_t count = points.size();
	if (count == 0) {
		result.push_back(Vector3());
		result.push_back(Vector3());
		result.push_back(Vector3());
		return result;
	}

	Vector3 centroid(0.0f, 0.0f, 0.0f);
	Vector3 min_bounds = points[0];
	Vector3 max_bounds = points[0];

	for (int64_t i = 0; i < count; i++) {
		const Vector3 &p = points[i];
		centroid.x += p.x;
		centroid.y += p.y;
		centroid.z += p.z;

		if (p.x < min_bounds.x) min_bounds.x = p.x;
		if (p.y < min_bounds.y) min_bounds.y = p.y;
		if (p.z < min_bounds.z) min_bounds.z = p.z;

		if (p.x > max_bounds.x) max_bounds.x = p.x;
		if (p.y > max_bounds.y) max_bounds.y = p.y;
		if (p.z > max_bounds.z) max_bounds.z = p.z;
	}

	float inv = 1.0f / static_cast<float>(count);
	centroid.x *= inv;
	centroid.y *= inv;
	centroid.z *= inv;

	result.push_back(centroid);
	result.push_back(min_bounds);
	result.push_back(max_bounds);
	return result;
}

float FastVectorMath::ray_sphere_intersection(const Vector3 &origin, const Vector3 &dir,
		const Vector3 &sphere_center, float radius) {
	// Solve ||origin + t*dir - sphere_center||^2 = radius^2
	Vector3 oc(
			origin.x - sphere_center.x,
			origin.y - sphere_center.y,
			origin.z - sphere_center.z);

	float a = dir.x * dir.x + dir.y * dir.y + dir.z * dir.z;
	float b = 2.0f * (oc.x * dir.x + oc.y * dir.y + oc.z * dir.z);
	float c = oc.x * oc.x + oc.y * oc.y + oc.z * oc.z - radius * radius;

	float discriminant = b * b - 4.0f * a * c;
	if (discriminant < 0.0f) {
		return -1.0f;
	}

	float sqrt_disc = std::sqrt(discriminant);
	float inv2a = 1.0f / (2.0f * a);

	float t1 = (-b - sqrt_disc) * inv2a;
	float t2 = (-b + sqrt_disc) * inv2a;

	if (t1 > 0.0f) {
		return t1;
	}
	if (t2 > 0.0f) {
		return t2;
	}
	return -1.0f;
}

#ifndef FAST_VECTOR_MATH_REGISTER_TYPES_H
#define FAST_VECTOR_MATH_REGISTER_TYPES_H

#include <godot_cpp/core/class_db.hpp>

using namespace godot;

void initialize_fast_vector_math_module(ModuleInitializationLevel p_level);
void uninitialize_fast_vector_math_module(ModuleInitializationLevel p_level);

#endif // FAST_VECTOR_MATH_REGISTER_TYPES_H

#include "register_types.h"

#include <gdextension_interface.h>
#include <godot_cpp/core/class_db.hpp>
#include <godot_cpp/core/defs.hpp>
#include <godot_cpp/godot.hpp>

#include "fast_vector_math.h"

using namespace godot;

void initialize_fast_vector_math_module(ModuleInitializationLevel p_level) {
	if (p_level != MODULE_INITIALIZATION_LEVEL_SCENE) {
		return;
	}
	GDREGISTER_CLASS(FastVectorMath);
}

void uninitialize_fast_vector_math_module(ModuleInitializationLevel p_level) {
	if (p_level != MODULE_INITIALIZATION_LEVEL_SCENE) {
		return;
	}
}

extern "C" {
GDExtensionBool GDE_EXPORT fast_vector_math_library_init(
		GDExtensionInterfaceGetProcAddress p_get_proc_address,
		GDExtensionClassLibraryPtr p_library,
		GDExtensionInitialization *r_initialization) {
	godot::GDExtensionBinding::InitObject init_obj(p_get_proc_address, p_library, r_initialization);

	init_obj.register_initializer(initialize_fast_vector_math_module);
	init_obj.register_terminator(uninitialize_fast_vector_math_module);
	init_obj.set_minimum_library_initialization_level(MODULE_INITIALIZATION_LEVEL_SCENE);

	return init_obj.init();
}
}

extends SceneTree

func _init() -> void:
	var all_passed := true

	# ── Guard: extension must be loaded ──────────────────────────────────────
	if not ClassDB.class_exists("FastVectorMath"):
		print("FAIL: FastVectorMath class not found – extension did not load")
		quit(1)
		return

	var fvm = ClassDB.instantiate("FastVectorMath")

	# ── Test 1: dot_product ──────────────────────────────────────────────────
	var a := Vector3(1.0, 2.0, 3.0)
	var b := Vector3(4.0, 5.0, 6.0)
	var dot: float = fvm.dot_product(a, b)          # 1*4 + 2*5 + 3*6 = 32
	if absf(dot - 32.0) < 1e-5:
		print("PASS: dot_product")
	else:
		print("FAIL: dot_product  expected=32.0  got=", dot)
		all_passed = false

	# ── Test 2: cross_product ────────────────────────────────────────────────
	var ax := Vector3(1.0, 0.0, 0.0)
	var ay := Vector3(0.0, 1.0, 0.0)
	var cross: Vector3 = fvm.cross_product(ax, ay)  # (0,0,1)
	if cross.is_equal_approx(Vector3(0.0, 0.0, 1.0)):
		print("PASS: cross_product")
	else:
		print("FAIL: cross_product  expected=(0,0,1)  got=", cross)
		all_passed = false

	# ── Test 3: compute_centroid_and_bounds ──────────────────────────────────
	var pts := PackedVector3Array([
		Vector3(-1.0, -1.0, -1.0),
		Vector3( 1.0,  1.0,  1.0),
	])
	var cbd: Array = fvm.compute_centroid_and_bounds(pts)
	var centroid: Vector3  = cbd[0]
	var min_b: Vector3     = cbd[1]
	var max_b: Vector3     = cbd[2]
	if  centroid.is_equal_approx(Vector3(0.0, 0.0, 0.0)) and \
		min_b.is_equal_approx(Vector3(-1.0, -1.0, -1.0)) and \
		max_b.is_equal_approx(Vector3( 1.0,  1.0,  1.0)):
		print("PASS: compute_centroid_and_bounds")
	else:
		print("FAIL: compute_centroid_and_bounds  centroid=", centroid,
			"  min=", min_b, "  max=", max_b)
		all_passed = false

	# ── Test 4: ray_sphere_intersection ──────────────────────────────────────
	# Ray along +Z, sphere centred at (0,0,5) r=1 → hit at t=4
	var origin  := Vector3(0.0, 0.0, 0.0)
	var dir     := Vector3(0.0, 0.0, 1.0)
	var scenter := Vector3(0.0, 0.0, 5.0)
	var t: float = fvm.ray_sphere_intersection(origin, dir, scenter, 1.0)
	if absf(t - 4.0) < 1e-4:
		print("PASS: ray_sphere_intersection")
	else:
		print("FAIL: ray_sphere_intersection  expected=4.0  got=", t)
		all_passed = false

	# ── Summary ───────────────────────────────────────────────────────────────
	if all_passed:
		print("ALL TESTS PASSED")
		quit(0)
	else:
		print("SOME TESTS FAILED")
		quit(1)
